import React, { useEffect, useState, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Check, Truck, ArrowLeft, Ruler, Scale, Flame, Info } from 'lucide-react';
import { CartContext } from '../context/CartContext';
import { useCategories } from '../context/CategoryContext';
import { getCategoryUrl } from '../utils/urls';
import api from '../api';

export default function ProductPage() {
    const { categorySlug, productSlug } = useParams();
    const [product, setProduct] = useState(null);
    const [loading, setLoading] = useState(true);
    const { addToCart } = useContext(CartContext);
    const { categories } = useCategories();

    // Some mock data to match drova.kiev.ua specs
    const specs = [
        { icon: <Ruler className="text-gray-400" size={18} />, label: "Довжина", value: "35-40 см" },
        { icon: <Scale className="text-gray-400" size={18} />, label: "Покол", value: "Середній" },
        { icon: <Flame className="text-gray-400" size={18} />, label: "Вологість", value: "До 25%" },
        { icon: <Info className="text-gray-400" size={18} />, label: "Фасування", value: "Навалом / склм" }
    ];

    useEffect(() => {
        window.scrollTo(0, 0);
        setLoading(true);
        // Assuming we have an endpoint that accepts a slug, or just grab all and filter for now
        api.get('/products/')
            .then(res => {
                const found = res.data.find(p => p.slug === productSlug);
                setProduct(found);
                setLoading(false);
            })
            .catch(err => {
                console.error("Failed fetching product", err);
                setLoading(false);
            });
    }, [productSlug]);

    const handleBuy = () => {
        if (product) {
            addToCart(product, 1, null, null, null, 'pickup');
            alert(`Товар "${product.name}" додано до кошика!`);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 flex justify-center items-center py-20">
                <div className="w-12 h-12 border-4 border-orange-200 border-t-orange-500 rounded-full animate-spin"></div>
            </div>
        );
    }

    if (!product) {
        return (
            <div className="min-h-screen bg-gray-50 text-center py-20">
                <h1 className="text-3xl font-bold mb-4">Товар не знайдено</h1>
                <Link to="/catalog/" className="text-orange-500 font-bold hover:underline">
                    Повернутися до каталогу
                </Link>
            </div>
        );
    }

    const imgUrl = product.image_url
        ? (product.image_url.startsWith('http') ? product.image_url : `${api.defaults.baseURL}${product.image_url}`)
        : '';

    const category = categories.find(c => c.slug === (categorySlug || (product && product.category)));

    return (
        <div className="min-h-screen bg-white">
            <div className="bg-gray-50 border-b border-gray-200 py-4 px-4 sm:px-8 xl:px-16">
                <div className="max-w-7xl mx-auto flex items-center gap-2 text-sm text-gray-500 font-medium">
                    <Link to="/" className="hover:text-orange-500 transition-colors">Головна</Link>
                    <span>/</span>
                    <Link to={category ? getCategoryUrl(category.slug) : "/catalog"} className="hover:text-orange-500 transition-colors">
                        {category ? category.name : "Каталог"}
                    </Link>
                    <span>/</span>
                    <span className="text-gray-900 line-clamp-1">{product.name}</span>
                </div>
            </div>

            <main className="max-w-screen-2xl mx-auto px-4 sm:px-8 xl:px-16 py-8 md:py-16">
                <div className="flex flex-col lg:flex-row gap-12 xl:gap-24 items-start">

                    {/* Left: Image - Increased from 1/2 to ~58% for 1.5x effect */}
                    <div className="w-full lg:w-[58%] flex-shrink-0 lg:sticky lg:top-32">
                        <div className="bg-gray-100 rounded-3xl overflow-hidden aspect-square sm:aspect-[4/3] lg:aspect-[5/6] relative flex items-center justify-center border border-gray-100 shadow-[0_32px_64px_-15px_rgba(0,0,0,0.15)]">
                            <div className="absolute top-8 left-8 z-10 bg-green-500 text-white text-xs font-bold px-4 py-2 rounded-lg uppercase tracking-wider shadow-lg">
                                В наявності
                            </div>
                            {imgUrl ? (
                                <img
                                    src={imgUrl}
                                    alt={product.name}
                                    className="w-full h-full object-cover transform hover:scale-105 transition-transform duration-1000 ease-out"
                                    style={{ imageRendering: 'high-quality' }}
                                />
                            ) : (
                                <span className="text-gray-400">Немає фото</span>
                            )}
                        </div>
                    </div>

                    {/* Right: Info */}
                    <div className="w-full lg:w-[42%] flex flex-col pt-2 lg:pt-0">
                        <h1 className="text-3xl md:text-4xl xl:text-5xl font-black text-gray-900 tracking-tight leading-tight mb-4">
                            {product.name}
                        </h1>

                        <div className="flex items-end gap-3 mb-8">
                            {product.price > 1000 && (
                                <span className="text-gray-400 line-through text-lg font-bold mb-1">
                                    {Math.round(product.price * 1.15)} грн
                                </span>
                            )}
                            <p className="text-orange-600 font-extrabold text-4xl leading-none">
                                {product.price} <span className="text-xl">грн</span>
                            </p>
                            <span className="text-sm text-gray-500 font-medium mb-1 ml-1">/ за складометр</span>
                        </div>

                        <div className="mb-10">
                            <button
                                onClick={handleBuy}
                                className="w-full sm:w-auto bg-orange-500 hover:bg-orange-600 active:scale-95 text-white px-10 py-4.5 rounded-xl font-bold text-lg transition-all shadow-lg flex items-center justify-center gap-3"
                            >
                                Купити в 1 клік
                            </button>
                        </div>

                        <div className="space-y-4 mb-10 pb-10 border-b border-gray-100">
                            <h3 className="text-lg font-bold text-gray-900 mb-2">Характеристики дров</h3>
                            <div className="grid grid-cols-2 gap-y-4 gap-x-6">
                                {specs.map((spec, i) => (
                                    <div key={i} className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center shrink-0">
                                            {spec.icon}
                                        </div>
                                        <div>
                                            <p className="text-xs text-gray-400 uppercase tracking-widest font-bold font-sans">{spec.label}</p>
                                            <p className="text-sm font-bold text-gray-900">{spec.value}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div>
                            <h3 className="text-xl font-bold text-gray-900 mb-4">Опис товару</h3>
                            <div className="prose prose-orange max-w-none text-gray-600 font-medium leading-relaxed">
                                <p>{product.description}</p>
                                <p className="mt-4">
                                    Наші дрова щільно укладені в кузові автомобіля (складометри),
                                    що гарантує чесний об'єм під час розвантаження.
                                    Оптимальний вибір для опалення приватних будинків, лазень та використання у камінах.
                                </p>
                            </div>
                        </div>

                        <div className="mt-8 bg-orange-50 rounded-xl p-5 border border-orange-100 flex items-start gap-4">
                            <Truck className="text-orange-500 mt-1 shrink-0" size={24} />
                            <div>
                                <h4 className="font-bold text-gray-900 text-sm mb-1">Швидка доставка по області</h4>
                                <p className="text-xs text-gray-600 font-medium">
                                    Доставляємо власним транспортом. Мінімальне замовлення від 1 склм.
                                    Оплата можлива готівкою при отриманні або на картку.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
}
